const file = process.argv[2];
const input = await FileBlob.load(file);
const wb = await SpreadsheetFile.importXlsx(input);
const overview = await wb.inspect({ kind: "workbook,sheet,table", maxChars: 12000, tableMaxRows: 12, tableMaxCols: 12, tableMaxCellChars: 100 });
console.log("---OVERVIEW---");
console.log(overview.ndjson);
const sheets = await wb.inspect({ kind: "sheet", include: "id,name", maxChars: 4000 });
console.log("---SHEETS---");
console.log(sheets.ndjson);
for (const line of sheets.ndjson.trim().split(/\r?\n/)) {
  if (!line.trim()) continue;
  let obj;
  try { obj = JSON.parse(line); } catch { continue; }
  const name = obj.name || obj.text || obj.id;
  if (!name) continue;
  console.log(`---REGION ${name} A1:Z40---`);
  try {
    const region = await wb.inspect({ kind: "region", sheetId: name, range: "A1:Z40", maxChars: 8000, tableMaxRows: 40, tableMaxCols: 26, tableMaxCellChars: 120 });
    console.log(region.ndjson);
  } catch (err) {
    console.log(JSON.stringify({ error: String(err), sheet: name }));
  }
  console.log(`---FORMULAS ${name} A1:Z100---`);
  try {
    const formulas = await wb.inspect({ kind: "formula", sheetId: name, range: "A1:Z100", maxChars: 5000, options: { maxResults: 80 } });
    console.log(formulas.ndjson);
  } catch (err) {
    console.log(JSON.stringify({ error: String(err), sheet: name }));
  }
}
