const fs = require('node:fs');
const path = require('node:path');
const port = Number(process.env.ALLOY_CDP_PORT);
const appUrl = process.env.ALLOY_APP_URL;
const downloadDir = process.env.ALLOY_DOWNLOAD_DIR;
const oldTemplate = process.env.ALLOY_OLD_TEMPLATE;
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

async function waitForChrome() {
  const deadline = Date.now() + 30000;
  while (Date.now() < deadline) {
    try {
      const response = await fetch(`[REDACTED_URL]);
      if (response.ok) return response.json();
    } catch {}
    await sleep(300);
  }
  throw new Error('Chrome CDP did not start');
}

class CDP {
  constructor(url) {
    this.url = url;
    this.id = 0;
    this.pending = new Map();
    this.events = [];
  }
  async connect() {
    this.ws = new WebSocket(this.url);
    this.ws.addEventListener('message', (event) => {
      const msg = JSON.parse(event.data);
      if (msg.id && this.pending.has(msg.id)) {
        const { resolve, reject } = this.pending.get(msg.id);
        this.pending.delete(msg.id);
        if (msg.error) reject(new Error(`${msg.error.message}: ${msg.error.data || ''}`));
        else resolve(msg.result || {});
      } else if (msg.method) {
        this.events.push(msg);
      }
    });
    await new Promise((resolve, reject) => {
      this.ws.addEventListener('open', resolve, { once: true });
      this.ws.addEventListener('error', reject, { once: true });
    });
  }
  send(method, params = {}) {
    const id = ++this.id;
    this.ws.send(JSON.stringify({ id, method, params }));
    return new Promise((resolve, reject) => {
      this.pending.set(id, { resolve, reject });
      setTimeout(() => {
        if (this.pending.has(id)) {
          this.pending.delete(id);
          reject(new Error(`CDP timeout: ${method}`));
        }
      }, 30000);
    });
  }
  close() { this.ws.close(); }
}

async function createPage() {
  await waitForChrome();
  const response = await fetch(`[REDACTED_URL])}`, { method: 'PUT' });
  if (!response.ok) throw new Error(`create target failed HTTP ${response.status}`);
  const target = await response.json();
  const cdp = new CDP(target.webSocketDebuggerUrl);
  await cdp.connect();
  await cdp.send('Page.enable');
  await cdp.send('Runtime.enable');
  await cdp.send('DOM.enable');
  try { await cdp.send('Page.setDownloadBehavior', { behavior: 'allow', downloadPath: downloadDir }); } catch (error) { console.error('download behavior warning:', error.message); }
  await waitFor(() => evalText(cdp, 'document.readyState') === 'complete', 30000, 'page load');
  return cdp;
}

async function evalValue(cdp, expression) {
  const result = await cdp.send('Runtime.evaluate', { expression, awaitPromise: true, returnByValue: true });
  if (result.exceptionDetails) throw new Error(result.exceptionDetails.text || 'Runtime exception');
  return result.result.value;
}

async function evalText(cdp, expression) {
  return evalValue(cdp, expression);
}

async function waitFor(fn, timeout, label) {
  const deadline = Date.now() + timeout;
  let last;
  while (Date.now() < deadline) {
    try {
      last = await fn();
      if (last) return last;
    } catch (error) {
      last = error.message;
    }
    await sleep(300);
  }
  throw new Error(`Timed out waiting for ${label}; last=${last}`);
}

async function waitForFile(prefix, suffix) {
  return waitFor(() => {
    const files = fs.readdirSync(downloadDir).filter((name) => name.startsWith(prefix) && name.endsWith(suffix) && !name.endsWith('.crdownload'));
    if (!files.length) return null;
    return path.join(downloadDir, files[0]);
  }, 30000, `${prefix} download`);
}

async function setFileInput(cdp, filePath) {
  const root = await cdp.send('DOM.getDocument', { depth: 1 });
  const query = await cdp.send('DOM.querySelector', { nodeId: root.root.nodeId, selector: '#batchFile' });
  if (!query.nodeId) throw new Error('batchFile input not found');
  await cdp.send('DOM.setFileInputFiles', { nodeId: query.nodeId, files: [filePath] });
  await evalValue(cdp, "document.getElementById('batchFile').dispatchEvent(new Event('change', { bubbles: true })); true");
}

async function validateAndRun(cdp, filePath, expectWarning) {
  await setFileInput(cdp, filePath);
  await evalValue(cdp, "document.getElementById('validateBatchButton').click(); true");
  await waitFor(async () => {
    const text = await evalText(cdp, "document.getElementById('batchStatus').textContent");
    return text.includes('预检通过') ? text : null;
  }, 30000, 'template validation');
  const badge = await evalText(cdp, "document.getElementById('batchStatusBadge').textContent");
  if (expectWarning && badge !== '有警告') throw new Error(`expected warning badge, got ${badge}`);
  await evalValue(cdp, "document.getElementById('runBatchButton').click(); true");
  await waitFor(async () => {
    const text = await evalText(cdp, "document.getElementById('batchStatus').textContent");
    return text.includes('批量计算完成') ? text : null;
  }, 30000, 'batch optimize');
  const summaryText = await evalText(cdp, "document.getElementById('batchStatus').textContent");
  if (!summaryText.includes('成功 2') || !summaryText.includes('失败 0')) throw new Error(`unexpected batch summary: ${summaryText}`);
  return { badge, summaryText };
}

(async () => {
  const cdp = await createPage();
  const errors = cdp.events.filter((event) => event.method === 'Runtime.exceptionThrown');
  const title = await evalText(cdp, 'document.title');
  const hasValidate = await evalValue(cdp, "typeof window.validateBatchTemplate === 'function'");
  const batchOpen = await evalValue(cdp, "document.querySelector('.batch-panel').hasAttribute('open')");
  if (!title || !hasValidate || batchOpen) throw new Error(`page state invalid title=${title} hasValidate=${hasValidate} batchOpen=${batchOpen}`);

  await evalValue(cdp, "document.getElementById('downloadTemplateButton').click(); true");
  const downloadedTemplate = await waitForFile('alloy-batch-template-v1', '.xlsx');
  const newResult = await validateAndRun(cdp, downloadedTemplate, false);

  await evalValue(cdp, "document.getElementById('exportBatchButton').click(); true");
  const exported = await waitForFile('alloy-batch-result-', '.xlsx');

  if (!fs.existsSync(oldTemplate)) throw new Error(`old template missing: ${oldTemplate}`);
  const oldResult = await validateAndRun(cdp, oldTemplate, true);

  const runtimeErrors = cdp.events.filter((event) => event.method === 'Runtime.exceptionThrown');
  if (runtimeErrors.length) throw new Error(`runtime exceptions: ${runtimeErrors.length}`);
  console.log(JSON.stringify({
    ok: true,
    title,
    downloadedTemplate,
    exported,
    newResult,
    oldResult,
    downloadDir
  }, null, 2));
  cdp.close();
})().catch((error) => {
  console.error(error.stack || error.message);
  process.exit(1);
});
